INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '83228b4d-3684-4acf-86ce-883947af95ef',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX + MLflow — Tracking, Registry, and Serving Your InferenceSession$escape$,
  $escape$MLflow has a first-class ONNX flavor via `mlflow.onnx`, which wraps your `onnxruntime.InferenceSession` through the full MLOps lifecycle. When logging, pass the raw `onnx.ModelProto` object — MLflow serializes it internally and records the opset version and IR version as run metadata automatically. Use `mlflow.onnx.log_model(onnx_model, artifact_path="model")` inside a run, then register it with `MlflowClient.create_model_version()` pointing to the run artifact URI. At serving time, `mlflow models serve -m models:/MyOnnxModel/Production -p 5001` spins up a REST endpoint that deserializes the proto, creates an `InferenceSession` with the default `CPUExecutionProvider`, and accepts JSON payloads with an `inputs` key mapping to named input tensors. For custom execution providers (CUDA, TensorRT), skip the built-in server — load via `mlflow.onnx.load_model()`, which returns the `ModelProto`, then wrap it yourself: `ort.InferenceSession(model.SerializeToString(), providers=["CUDAExecutionProvider"])`. Combine this with MLflow Projects to pin the `onnxruntime` version and opset in `MLproject` for reproducible training pipelines.$escape$,
  $escape$import mlflow
import mlflow.onnx
import onnxruntime as ort

with mlflow.start_run():
    mlflow.onnx.log_model(onnx_model_proto, artifact_path="model")
    run_id = mlflow.active_run().info.run_id

client = mlflow.MlflowClient()
model_uri = f"runs:/{run_id}/model"
client.create_registered_model("MyOnnxModel")
client.create_model_version(name="MyOnnxModel", source=model_uri, run_id=run_id)

# Load and wrap with custom EP
proto = mlflow.onnx.load_model("models:/MyOnnxModel/Production")
sess = ort.InferenceSession(
    proto.SerializeToString(),
    providers=["CUDAExecutionProvider", "CPUExecutionProvider"]
)$escape$,
  $escape$python$escape$,
