INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bbe2cd07-3796-41c7-abc9-b97655f4397c',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX Runtime Tuning with W&B — Sweep SessionOptions, Not Guesswork$escape$,
  $escape$ONNX Runtime performance is highly sensitive to SessionOptions — graph_optimization_level, intra_op_num_threads, execution_mode, and execution provider ordering all interact non-linearly. Manually tuning these is guesswork. W&B Sweeps with Bayesian optimization turns it into a proper search.

Define a sweep config targeting GraphOptimizationLevel values (ORT_ENABLE_BASIC=1, ORT_ENABLE_EXTENDED=2, ORT_ENABLE_ALL=99) and thread counts, then let wandb.agent drive ort.InferenceSession construction across trials. Log latency_ms or throughput as the metric. After 20–30 runs, W&B's parallel coordinates plot in Reports reveals which SessionOptions combos dominate — often ORT_ENABLE_ALL with 4 intra_op_num_threads outperforms the naive all-cores default due to NUMA contention.

For multi-EP models, extend the sweep to include providers ordering (["CUDAExecutionProvider", "CPUExecutionProvider"] vs ["TensorrtExecutionProvider", ...]) and enable per-node profiling via sess_options.enable_profiling=True to log node-level hotspots as W&B artifacts. W&B Reports let you diff these runs side-by-side — shareable links make EP trade-off decisions reviewable by the whole team without re-running locally.$escape$,
  $escape$import wandb, onnxruntime as ort, numpy as np, time

sweep_config = {
    "method": "bayes",
    "metric": {"name": "latency_ms", "goal": "minimize"},
    "parameters": {
        "graph_opt_level": {"values": [1, 2, 99]},
        "intra_op_threads": {"min": 1, "max": 8},
    },
}

def run():
    wandb.init()
    opts = ort.SessionOptions()
    opts.graph_optimization_level = ort.GraphOptimizationLevel(wandb.config.graph_opt_level)
    opts.intra_op_num_threads = wandb.config.intra_op_threads
    sess = ort.InferenceSession("model.onnx", sess_options=opts, providers=["CPUExecutionProvider"])
    x = np.random.randn(1, 3, 224, 224).astype(np.float32)
    [sess.run(None, {"input": x}) for _ in range(10)]  # warmup
    t = time.perf_counter()
    [sess.run(None, {"input": x}) for _ in range(100)]
    wandb.log({"latency_ms": (time.perf_counter() - t) * 10})

sweet_id = wandb.sweep(sweep_config, project="onnx-rt-tuning")
wandb.agent(sweet_id, run, count=20)$escape$,
  $escape$python$escape$,
