INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e643014d-feed-4b7d-ab11-a18b9d03382f',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX Model Versioning with DVC — Reproducible ML Pipelines for ONNX Exports$escape$,
  $escape$When you export a PyTorch or TensorFlow model to ONNX format, the resulting `.onnx` file is a binary artifact that changes with every retrain. Without versioning, you lose traceability between your training data, preprocessing logic, and the specific opset-level graph that went to production. DVC solves this by treating your `.onnx` files as first-class versioned artifacts, stored remotely (S3, Azure Blob, GCS) while only a lightweight `.dvc` pointer file lives in Git.

Define a DVC pipeline with stages: `preprocess → train → export_onnx → validate_onnx`. The `export_onnx` stage runs `torch.onnx.export()` with a pinned `opset_version` and outputs `model.onnx` as a tracked artifact. The `validate_onnx` stage runs `onnxruntime.InferenceSession` against a golden input/output fixture to catch shape or dtype regressions before the model reaches your serving layer. With `dvc repro`, the entire pipeline reruns only when upstream deps (data hash, training script, opset config) change — giving you byte-for-byte reproducible ONNX graphs tied to a Git commit.$escape$,
  $escape$# dvc.yaml
stages:
  export_onnx:
    cmd: python export.py --opset 17 --output model.onnx
    deps:
      - train/model.pt
      - export.py
    params:
      - params.yaml:
          - opset_version
    outs:
      - model.onnx

  validate_onnx:
    cmd: python validate.py --model model.onnx --fixture tests/golden.npz
    deps:
      - model.onnx
      - validate.py
      - tests/golden.npz$escape$,
  $escape$bash$escape$,
