INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '95462ec1-de15-4860-80f0-1594dd510271',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX Runtime — Export PyTorch Models and Run Inference Across Frameworks$escape$,
  $escape$ONNX (Open Neural Network Exchange) gives you a single serialized graph that any compliant runtime can execute — PyTorch, TensorFlow, and scikit-learn all export to it. The export process freezes your model into a static computational graph: `torch.onnx.export()` traces through a forward pass using dummy inputs, capturing every op as an ONNX node. Dynamic axes let you preserve variable batch sizes or sequence lengths without re-exporting. Once you have the `.onnx` file, `onnxruntime.InferenceSession` loads it — no Python ML framework required at inference time. ORT selects an execution provider automatically (CPUExecutionProvider, CUDAExecutionProvider, TensorrtExecutionProvider) based on availability. Input names must exactly match those registered during export — mismatches throw at session creation, not at `run()`. Use `onnx.checker.check_model()` before deployment to validate graph integrity and opset compatibility. Opset version matters: exporting at opset 17 may produce ops unsupported by older ORT builds. Pin both together in CI. For quantization, `onnxruntime.quantization.quantize_dynamic()` converts float32 weights to int8 post-export with no retraining.$escape$,
  $escape$import torch
import onnxruntime as ort
import numpy as np

# Export
model = MyModel().eval()
dummy = torch.randn(1, 3, 224, 224)
torch.onnx.export(
    model, dummy, "model.onnx",
    opset_version=17,
    input_names=["image"],
    output_names=["logits"],
    dynamic_axes={"image": {0: "batch"}, "logits": {0: "batch"}}
)

# Inference
sess = ort.InferenceSession("model.onnx", providers=["CUDAExecutionProvider", "CPUExecutionProvider"])
output = sess.run(["logits"], {"image": np.random.randn(4, 3, 224, 224).astype(np.float32)})
print(output[0].shape)  # (4, num_classes)$escape$,
  $escape$python$escape$,
