INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4ed0c055-b114-43d4-8706-7c26051bf769',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX + TensorRT — Building Optimized Engines with Quantization and Latency Control$escape$,
  $escape$When you export a model to ONNX and target NVIDIA hardware, TensorRT is your fastest path to production-grade latency. The bridge is `tensorrt` (via `trtexec`) or the Python `tensorrt` API — both consume `.onnx` files directly. TensorRT parses your ONNX graph, fuses ops (e.g., Conv+BN+ReLU into a single kernel), and compiles a hardware-specific `.engine` file. INT8 quantization requires a calibration dataset; TensorRT runs inference passes to compute activation ranges per tensor, minimizing accuracy loss. FP16 is lossless for most vision models and cuts latency ~40% on Ampere+. Critical caveat: engines are GPU-architecture-specific — an engine built on an A100 won't run on a T4. At runtime, load the engine with `trt.Runtime`, deserialize it, and bind input/output buffers via `IExecutionContext.execute_async_v2()`. Always profile with `trtexec --onnx=model.onnx --fp16 --best` before committing to a precision mode — latency vs. accuracy tradeoffs are model-dependent and non-obvious.$escape$,
  $escape$import tensorrt as trt
import numpy as np

TRT_LOGGER = trt.Logger(trt.Logger.WARNING)

def build_engine(onnx_path: str, fp16: bool = True) -> trt.ICudaEngine:
    with trt.Builder(TRT_LOGGER) as builder, \
         builder.create_network(1 << int(trt.NetworkDefinitionCreationFlag.EXPLICIT_BATCH)) as network, \
         trt.OnnxParser(network, TRT_LOGGER) as parser:
        config = builder.create_builder_config()
        config.set_memory_pool_limit(trt.MemoryPoolType.WORKSPACE, 1 << 30)  # 1GB
        if fp16 and builder.platform_has_fast_fp16:
            config.set_flag(trt.BuilderFlag.FP16)
        with open(onnx_path, "rb") as f:
            parser.parse(f.read())
        return builder.build_serialized_network(network, config)$escape$,
  $escape$python$escape$,
