INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '59e8c1e5-1dc7-4847-8c18-34b2616223e9',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX + Ray — HPO to Production Without a Framework Switch$escape$,
  $escape$Ray Tune runs HPO trials across a cluster, each training a separate model variant in parallel. Once `tune.run()` completes, `result.get_best_checkpoint()` returns the winning trial's checkpoint — export it immediately with `torch.onnx.export(model, dummy_input, "best.onnx", opset_version=17, dynamic_axes={"input": {0: "batch"}})`. Setting `dynamic_axes` on the batch dimension is non-negotiable if Ray Serve will handle variable-size payloads.

Ray Serve's `@serve.deployment` initializes an `ort.InferenceSession` once per replica inside `__init__`, not per request. Set `GraphOptimizationLevel.ORT_ENABLE_ALL` and pass `providers=["CUDAExecutionProvider", "CPUExecutionProvider"]` for automatic GPU fallback. Use `session.get_inputs()[0].name` instead of hardcoding — Tune trials across architectures produce ONNX graphs with different input names.

For horizontal scale, increment `num_replicas`; Ray Serve load-balances across ORT sessions. Enable `SessionOptions.enable_mem_pattern = True` and batch requests inside `__call__` to saturate throughput. Ray's actor isolation means each replica owns its session exclusively, eliminating the GIL contention that makes threading-based ONNX Runtime servers hit a ceiling under concurrent load.$escape$,
  $escape$import ray
from ray import serve
import onnxruntime as ort
import numpy as np

@serve.deployment(num_replicas=2, ray_actor_options={"num_cpus": 2})
class ONNXServeDeployment:
    def __init__(self, model_path: str):
        opts = ort.SessionOptions()
        opts.graph_optimization_level = ort.GraphOptimizationLevel.ORT_ENABLE_ALL
        opts.enable_mem_pattern = True
        self.session = ort.InferenceSession(
            model_path, opts,
            providers=["CUDAExecutionProvider", "CPUExecutionProvider"]
        )
        self.input_name = self.session.get_inputs()[0].name

    async def __call__(self, request):
        data = await request.json()
        feeds = {self.input_name: np.array(data["inputs"], dtype=np.float32)}
        return {"predictions": self.session.run(None, feeds)[0].tolist()}

app = ONNXServeDeployment.bind(model_path="/models/best.onnx")$escape$,
  $escape$python$escape$,
