INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '115cdbcf-9a18-458c-88f3-88bcc1600f79',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX Runtime — Building Low-Latency REST Inference APIs with Dynamic Batching$escape$,
  $escape$ONNX Runtime's `InferenceSession` is your inference engine — but wrapping it in a REST API without careful design will blow your latency SLAs immediately. The critical path: reuse a single `InferenceSession` across requests (initialization costs 100ms–2s depending on model size and EP), and use `SessionOptions` to pin thread counts via `inter_op_num_threads` and `intra_op_num_threads` to avoid CPU thrashing under load.

For batching, don't wait for a fixed batch size — use a time-bounded queue (e.g., 10ms window) to accumulate requests, then construct a single `numpy` array along axis 0 and run one `session.run()` call. This collapses N separate inference calls into one, leveraging ONNX Runtime's vectorized execution across the batch dimension natively.

Set your SLA budget: P99 < 50ms for small models on CPU EP, P99 < 10ms on CUDA EP with `CUDAExecutionProvider` + `cudnn_conv_algo_search = EXHAUSTIVE`. Profile with `session.run()` timestamps, not framework middleware — middleware overhead is invisible otherwise. Use `IOBinding` to keep tensors on-device between requests when chaining models.$escape$,
  $escape$import onnxruntime as ort
import numpy as np
from fastapi import FastAPI
import asyncio, time

app = FastAPI()
opts = ort.SessionOptions()
opts.intra_op_num_threads = 4
opts.inter_op_num_threads = 2
session = ort.InferenceSession("model.onnx", opts, providers=["CUDAExecutionProvider", "CPUExecutionProvider"])

batch_queue: list = []
BATCH_WINDOW_MS = 10

@app.post("/infer")
async def infer(data: list[float]):
    future = asyncio.get_event_loop().create_future()
    batch_queue.append((np.array(data, dtype=np.float32), future))
    await asyncio.sleep(BATCH_WINDOW_MS / 1000)
    if not future.done():
        inputs, futures = zip(*batch_queue[:])
        batch_queue.clear()
        batch = np.stack(inputs, axis=0)
        t0 = time.perf_counter()
        outputs = session.run(None, {session.get_inputs()[0].name: batch})
        latency_ms = (time.perf_counter() - t0) * 1000
        for i, f in enumerate(futures):
            f.set_result({"output": outputs[0][i].tolist(), "latency_ms": latency_ms})
    return await future$escape$,
  $escape$python$escape$,
