INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '26eefd99-7fce-4871-a79b-919ee6fcd373',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX Runtime — Detecting Model Drift in Production Without Rebuilding Your Pipeline$escape$,
  $escape$ONNX Runtime has no built-in monitoring hooks, so drift detection means wrapping your InferenceSession. The key insight: use raw logits from session.run() as your monitoring signal—not just the argmax—since distribution shape degrades before accuracy visibly drops.

For prediction drift, maintain a rolling window of output tensors and compute L2 distance against a baseline distribution serialized at deploy time (numpy .npy works fine). Threshold on that norm-distance gives early warnings days before accuracy metrics move.

For data drift, intercept inputs before session.run(). Use session.get_inputs() to enumerate named inputs with their expected dtypes and shapes, then log per-dimension mean/std against deployment-time statistics. Population Stability Index (PSI > 0.2 signals significant shift) works well here since it's distribution-agnostic.

For performance degradation, set enable_profiling=True on SessionOptions during periodic sampling runs—never every request. Call session.end_profiling() to get a Chrome-trace JSON. Alert when p99 latency on heavy nodes (MatMul, Gather, LayerNorm) exceeds 2× your deployment baseline. This catches provider-level regressions when CUDA drivers or ExecutionProvider configs change under you.$escape$,
  $escape$import onnxruntime as ort
import numpy as np
from collections import deque

session = ort.InferenceSession("model.onnx", providers=["CUDAExecutionProvider"])
baseline_mean = np.load("baseline_logits_mean.npy")  # saved at deploy time
window: deque = deque(maxlen=1000)
input_name = session.get_inputs()[0].name

def run_monitored(x: np.ndarray) -> np.ndarray:
    logits = session.run(None, {input_name: x})[0]
    window.extend(logits.tolist())
    if len(window) == 1000:
        drift = np.linalg.norm(np.mean(window, axis=0) - baseline_mean)
        if drift > 0.15:
            print(f"[PREDICTION DRIFT] L2={drift:.4f}")
    return logits$escape$,
  $escape$python$escape$,
