INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '563e1864-2f1a-4fef-8903-02637a10d271',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX CI/CD Pipelines — Automated Evaluation Gates Before Deployment$escape$,
  $escape$Shipping ML models safely requires more than just exporting to ONNX — it demands structured gates at every stage of the pipeline. Start with a structural gate: run `onnx.checker.check_model()` and `onnx.shape_inference.infer_shapes()` immediately post-export to catch malformed graphs before they hit staging. Pin your opset version explicitly (`opset_imports`) in CI config so runtime upgrades don't silently break operator support.

The critical gate is the evaluation gate: load the `.onnx` artifact with `onnxruntime.InferenceSession`, run it against a frozen validation set, and assert metric thresholds in code — not in a human review step. If `accuracy < 0.94` or `p99_latency_ms > 8`, the pipeline fails and the old model stays live.

For retraining triggers, compare the new model's `onnx.ModelProto.metadata_props` (embed git SHA, dataset hash, eval scores as custom metadata) against the production artifact. Only promote if metrics improve or stay within tolerance. Store artifacts in versioned blob storage and deploy via a blue-green swap that swaps the ORT session pointer atomically — no downtime, instant rollback.$escape$,
  $escape$import onnx
import onnxruntime as ort
import numpy as np

def evaluation_gate(model_path: str, val_inputs: np.ndarray, val_labels: np.ndarray, threshold: float = 0.94) -> bool:
    onnx.checker.check_model(onnx.load(model_path))

    sess = ort.InferenceSession(model_path, providers=["CPUExecutionProvider"])
    input_name = sess.get_inputs()[0].name
    logits = sess.run(None, {input_name: val_inputs})[0]

    preds = np.argmax(logits, axis=1)
    accuracy = (preds == val_labels).mean()

    print(f"Validation accuracy: {accuracy:.4f} (threshold: {threshold})")
    return float(accuracy) >= threshold$escape$,
  $escape$python$escape$,
