INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '13a8a1db-ec46-45b5-aa50-614e17eaa6fb',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX Quantization — INT8, FP16, and When Each Actually Wins$escape$,
  $escape$ONNX Runtime's quantization tools let you shrink models without retraining. Static INT8 quantization via `quantize_static()` requires a calibration dataset to compute activation ranges — it yields the smallest models (~4× vs FP32) and fastest CPU inference, but accuracy can slip 1–3% on sensitive tasks. Dynamic quantization (`quantize_dynamic()`) skips calibration by computing ranges at runtime; safer for NLP/transformer weights, but slower due to per-operator overhead. FP16 (`convert_float_to_float16()` from `onnxmltools`) is the sweet spot for GPU paths — near-lossless precision with ~2× memory reduction, zero calibration needed. Pruning is separate: ONNX has no native pruning API, so you prune in PyTorch/TensorFlow first, export to ONNX, then quantize. After quantizing, always validate with `onnx.checker.check_model()` and benchmark with `ort.InferenceSession` using `providers=['CPUExecutionProvider']` vs `CUDAExecutionProvider` — provider choice changes which quantized ops get hardware acceleration. Watch for `QuantizeLinear`/`DequantizeLinear` node pairs in Netron; excessive Q/DQ wrapping kills the speedup.$escape$,
  $escape$import onnxruntime.quantization as ortq

# Static INT8 — needs calibration data
ortq.quantize_static(
    model_input="model.onnx",
    model_output="model_int8.onnx",
    calibration_data_reader=my_calibration_reader,
    quant_format=ortq.QuantFormat.QDQ,
    activation_type=ortq.QuantType.QInt8,
    weight_type=ortq.QuantType.QInt8,
)

# Dynamic INT8 — no calibration, safer for transformers
ortq.quantize_dynamic(
    model_input="model.onnx",
    model_output="model_dynamic_int8.onnx",
    weight_type=ortq.QuantType.QInt8,
)$escape$,
  $escape$python$escape$,
