INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a0d65893-6c51-4367-bea1-867c0d77778c',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX A/B Testing — Shadow Deployment, Canary Releases, and Champion/Challenger$escape$,
  $escape$Running multiple ONNX models in production simultaneously is straightforward because each InferenceSession is stateless and thread-safe. Shadow deployment means loading both champion and challenger sessions, routing all live traffic to the champion, but asynchronously running the challenger on the same input — comparing outputs without user impact. Use a ConcurrentDictionary<string, InferenceSession> keyed by model variant to manage sessions loaded from versioned .onnx files.

For canary releases, maintain a weighted router: hash the request ID modulo 100 and route to the challenger session if the value falls below your canary percentage (e.g., 5). Both sessions share the same OrtEnvironment singleton — instantiating multiple environments wastes memory and thread pools.

Champion/challenger requires metric collection per session. Tag each InferenceSession with metadata (model version, quantization level, opset) and emit latency and accuracy signals to your observability layer. ONNX Runtime's SessionOptions.AppendExecutionProvider_CUDA lets you pin challenger models to a secondary GPU, isolating resource contention from the champion entirely. Swap champion by atomically replacing the dictionary entry — no restart needed.$escape$,
  $escape$using Microsoft.ML.OnnxRuntime;
using System.Collections.Concurrent;

var env = OrtEnvironment.GetEnvironment();
var sessions = new ConcurrentDictionary<string, InferenceSession>
{
    ["champion"] = new InferenceSession("model_v1.onnx"),
    ["challenger"] = new InferenceSession("model_v2.onnx")
};

string RouteVariant(string requestId, int canaryPct) =>
    Math.Abs(requestId.GetHashCode()) % 100 < canaryPct ? "challenger" : "champion";

var variant = RouteVariant(requestId, canaryPct: 5);
var results = sessions[variant].Run(inputs);$escape$,
  $escape$csharp$escape$,
