INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0a30c9f4-f07b-40fd-bda7-e508bd8d01cb',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX + skl2onnx — Freeze Feature Pipelines and Catch Data Drift at Serving Time$escape$,
  $escape$Freezing your sklearn preprocessing pipeline as an ONNX graph with skl2onnx eliminates training-serving skew — the same StandardScaler, SimpleImputer, and feature transforms run identically in Python, C#, or C++ via ONNX Runtime. `convert_sklearn()` serializes the full sklearn Pipeline into an ONNX protobuf, storing fitted statistics (mean, variance, fill values) inside the graph's initializer tensors.

For data validation, `InferenceSession.get_inputs()` exposes the expected tensor shape and dtype at runtime. Assert live data against these specs to catch schema drift — feature count mismatches, column reordering, or unexpected type promotions — before they silently corrupt inference outputs.

For statistical drift, export a second ONNX model trained on training-set feature distributions (e.g., a KernelDensity estimator via skl2onnx or a custom graph using `onnx.helper.make_graph`). Run both sessions back-to-back in your serving loop: the feature pipeline transforms inputs, the drift detector scores them. Because both are native ONNX Runtime sessions, there's no Python overhead between steps. On CPU, drift scoring a 512-row, 10-feature batch typically adds under 1ms — cheap enough to run on every request.$escape$,
  $escape$from skl2onnx import convert_sklearn
from skl2onnx.common.data_types import FloatTensorType
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.impute import SimpleImputer
import onnxruntime as rt
import numpy as np

pipe = Pipeline([("imputer", SimpleImputer()), ("scaler", StandardScaler())])
pipe.fit(X_train)

onnx_model = convert_sklearn(pipe, initial_types=[("X", FloatTensorType([None, X_train.shape[1]]))])
with open("feat_pipe.onnx", "wb") as f:
    f.write(onnx_model.SerializeToString())

sess = rt.InferenceSession("feat_pipe.onnx")
meta = sess.get_inputs()[0]
assert X_live.shape[1] == meta.shape[1], f"Schema drift: expected {meta.shape[1]} features, got {X_live.shape[1]}"
out = sess.run(None, {"X": X_live.astype(np.float32)})[0]$escape$,
  $escape$python$escape$,
