INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '65d54082-9865-4e87-8d59-43d41e7f9c40',
  '00000000-0000-0000-0000-000000000001',
  $escape$ONNX Runtime on Spot Clusters — Checkpoint Resilience and CUDA Arena Tuning$escape$,
  $escape$Spot instance preemptions are the biggest threat to long ONNX Runtime training runs. ORT's `onnxruntime.training.api.CheckpointState` combined with `TrainingSession.save_checkpoint()` gives you a portable, fast-serializing recovery point that reloads in seconds — critical when a preempted node rejoins a cluster mid-epoch.

On the GPU memory side, ORT's CUDA execution provider exposes `arena_extend_strategy` and `gpu_mem_limit` in `CUDAExecutionProviderOptions`. Setting `arena_extend_strategy=1` (kSameAsRequested) avoids ORT's default aggressive pre-allocation, which can cause OOM on shared spot nodes. Pair this with `do_copy_in_default_stream=False` to overlap H2D transfers with compute on multi-stream setups.

For multi-GPU spot clusters, pin `OrtValueInfo` bindings via `IOBinding` rather than re-allocating device buffers each checkpoint restore — this cuts cold-start latency by 30–60% on A100 nodes. Use `SessionOptions.add_session_config_entry('session.use_device_allocator_for_initializers', '1')` to keep frozen weights in the CUDA arena across checkpoint cycles, avoiding repeated PCIe transfers on node recovery.$escape$,
  $escape$import onnxruntime.training.api as orttraining
import onnxruntime as ort

cuda_opts = ort.CUDAExecutionProviderOptions()
cuda_opts.arena_extend_strategy = 1          # kSameAsRequested — no over-alloc
cuda_opts.gpu_mem_limit = 20 * 1024**3       # 20 GB cap for shared spot node
cuda_opts.do_copy_in_default_stream = False  # overlap H2D with compute

checkpoint_state = orttraining.CheckpointState.load_checkpoint("ckpt.ortckpt")
model = orttraining.Module("model.onnx", checkpoint_state, "loss.onnx",
                           device="cuda", providers=[("CUDAExecutionProvider", cuda_opts)])

# Save on SIGTERM (spot preemption signal)
import signal
signal.signal(signal.SIGTERM, lambda s, f: orttraining.CheckpointState.save_checkpoint(checkpoint_state, "ckpt.ortckpt"))$escape$,
  $escape$python$escape$,
